For the Canvas approach in Compose:

```kotlin
@Composable
fun OcrDebugScreen(image: Bitmap, textBoxes: List<TextBox>, onBackClicked: () -> Unit) {
    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("OCR Debug") },
                navigationIcon = {
                    IconButton(onClick = onBackClicked) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(16.dp)
        ) {
            // Image with bounding boxes
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .aspectRatio(image.width.toFloat() / image.height.toFloat())
            ) {
                Image(
                    bitmap = image.asImageBitmap(),
                    contentDescription = null,
                    modifier = Modifier.fillMaxSize()
                )

                Canvas(modifier = Modifier.fillMaxSize()) {
                    val scaleX = size.width / image.width
                    val scaleY = size.height / image.height

                    textBoxes.forEach { box ->
                        val ((x1, y1), (x2, y2)) = box.bounds
                        drawRect(
                            color = Color.Red,
                            topLeft = Offset(x1 * scaleX, y1 * scaleY),
                            size = Size((x2 - x1) * scaleX, (y2 - y1) * scaleY),
                            style = Stroke(width = 2.dp.toPx())
                        )
                    }
                }
            }

            // Text list
            Spacer(modifier = Modifier.height(16.dp))
            Text("Recognized Text:", style = MaterialTheme.typography.titleMedium)
            Spacer(modifier = Modifier.height(8.dp))

            LazyColumn(modifier = Modifier.fillMaxSize()) {
                items(textBoxes) { box ->
                    Text("${box.text} (score: ${"%.2f".format(box.score)})")
                }
            }
        }
    }
}
```

